"use strict";(self.webpackChunkplvacc_wiki=self.webpackChunkplvacc_wiki||[]).push([["1924"],{5226(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"defaultSidebar":[{"type":"link","href":"/","label":"Strona startowa","docId":"welcome","unlisted":false},{"type":"category","label":"Regulaminy","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/regulations/atc-school-requlations","label":"Regulamin Szko\u0142y Kontroler\xf3w w PLVACC","docId":"regulations/atc-school-requlations","unlisted":false}],"href":"/category/regulaminy"},{"type":"category","label":"Zagadnienia og\xf3lne","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/basic/air-traffic-management-radiotelephony","label":"Radiotelefonia i frazeologia","docId":"basic/air-traffic-management-radiotelephony","unlisted":false},{"type":"category","label":"Zarz\u0105dzanie ruchem lotniczym","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/basic/air-traffic-management/air-traffic-management-ATC-transmissions","label":"Zezwolenia i instrukcje ATC","docId":"basic/air-traffic-management/air-traffic-management-ATC-transmissions","unlisted":false},{"type":"link","href":"/basic/air-traffic-management/air-traffic-management-flight-levels","label":"Poziomy lotu","docId":"basic/air-traffic-management/air-traffic-management-flight-levels","unlisted":false},{"type":"link","href":"/basic/air-traffic-management/air-traffic-management-practical-skills","label":"Podstawowe umiej\u0119tno\u015Bci praktyczne znajduj\u0105ce zastosowanie w ruchu lotniczym","docId":"basic/air-traffic-management/air-traffic-management-practical-skills","unlisted":false}],"href":"/basic/air-traffic-management/"},{"type":"category","label":"aircraft","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/basic/aircraft/aircraft","label":"Statki powietrzne","docId":"basic/aircraft/aircraft","unlisted":false}]},{"type":"category","label":"Prawo lotnicze","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/basic/aviation-law/aviation-law-intro","label":"Wprowadzenie do prawa lotniczego","docId":"basic/aviation-law/aviation-law-intro","unlisted":false},{"type":"link","href":"/basic/aviation-law/aviation-law-organisations","label":"Instytucje mi\u0119dzynarodowe w kontek\u015Bcie VATSIM","docId":"basic/aviation-law/aviation-law-organisations","unlisted":false},{"type":"link","href":"/basic/aviation-law/aviation-law-polish-orgs","label":"Lokalne organizacje istotne dla VATSIM","docId":"basic/aviation-law/aviation-law-polish-orgs","unlisted":false},{"type":"link","href":"/basic/aviation-law/aviation-law-airspace","label":"Przestrze\u0144 powietrzna","docId":"basic/aviation-law/aviation-law-airspace","unlisted":false}],"href":"/basic/aviation-law/"},{"type":"link","href":"/basic/equipment/","label":"Urz\u0105dzenia i systemy","docId":"basic/equipment/equipment","unlisted":false},{"type":"link","href":"/basic/general","label":"Zagadnienia og\xf3lne","docId":"basic/general","unlisted":false},{"type":"category","label":"Czynniki ludzkie","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/basic/human-factor/human-factor-principles","label":"Podej\u015Bcie do innych u\u017Cytkownik\xf3w","docId":"basic/human-factor/human-factor-principles","unlisted":false}],"href":"/basic/human-factor/"},{"type":"category","label":"Meteorologia update","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/basic/meteorology/meteorology-basics","label":"Podstawowe zjawiska meteorologiczne oraz ich wp\u0142yw na lotnictwo","docId":"basic/meteorology/meteorology-basics","unlisted":false},{"type":"link","href":"/basic/meteorology/meteorology-sources","label":"\u0179r\xf3d\u0142a danych meteorologicznych","docId":"basic/meteorology/meteorology-sources","unlisted":false},{"type":"link","href":"/basic/meteorology/clouds","label":"clouds","docId":"basic/meteorology/clouds","unlisted":false}],"href":"/basic/meteorology/"},{"type":"link","href":"/basic/navigation/","label":"Nawigacja","docId":"basic/navigation/navigation","unlisted":false},{"type":"category","label":"special_unsafe_situations","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/basic/special_unsafe_situations/special-and-unsafe-situations","label":"Sytuacje szczeg\xf3lne i niebezpieczne","docId":"basic/special_unsafe_situations/special-and-unsafe-situations","unlisted":false}]}],"href":"/category/zagadnienia-og\xf3lne"},{"type":"category","label":"Rating S1","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/s1/","label":"Rating S1","docId":"s1/S1","unlisted":false},{"type":"category","label":"aerodrome","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/s1/aerodrome/aerodromes","label":"Lotniska","docId":"s1/aerodrome/aerodromes","unlisted":false}]},{"type":"category","label":"Clearance - delivery","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/s1/delivery/delivery-flight-plan-validation","label":"Sprawdzenie poprawno\u015Bci planu lotu","docId":"s1/delivery/delivery-flight-plan-validation","unlisted":false}],"href":"/s1/delivery/"},{"type":"link","href":"/s1/ground/","label":"Kontroler ground","docId":"s1/ground/ground","unlisted":false}],"href":"/category/rating-s1"},{"type":"category","label":"Rating S2","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/s2/","label":"Rating S2","docId":"s2/S2","unlisted":false}],"href":"/category/rating-s2"},{"type":"category","label":"Demo do kalibracji","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Kontroler GND","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/test/gnd-ground/GND-duties","label":"Zakres obowi\u0105zk\xf3w","docId":"test/gnd-ground/GND-duties","unlisted":false},{"type":"link","href":"/test/gnd-ground/push-and-start","label":"Wypychanie i uruchamianie","docId":"test/gnd-ground/push-and-start","unlisted":false},{"type":"link","href":"/test/gnd-ground/GND-movement","label":"Ruch na p\u0142ycie","docId":"test/gnd-ground/GND-movement","unlisted":false},{"type":"link","href":"/test/gnd-ground/parking-stand-allocation","label":"Przydzielanie stanowisk","docId":"test/gnd-ground/parking-stand-allocation","unlisted":false},{"type":"link","href":"/test/gnd-ground/conditional-instructions","label":"Instrukcje warunkowe","docId":"test/gnd-ground/conditional-instructions","unlisted":false},{"type":"link","href":"/test/gnd-ground/deicing","label":"Odladzanie","docId":"test/gnd-ground/deicing","unlisted":false}],"href":"/category/kontroler-gnd"},{"type":"link","href":"/test/airspace","label":"Przestrze\u0144 powietrzna","docId":"test/airspace","unlisted":false},{"type":"link","href":"/test/arrivals-management","label":"1. Zarz\u0105dzanie przylotami","docId":"test/arrivals-management","unlisted":false},{"type":"link","href":"/test/flight-plan-validation","label":"1. Sprawdzenie poprawno\u015Bci planu lotu.","docId":"test/flight-plan-validation","unlisted":false},{"type":"link","href":"/test/parking-stand-allocation","label":"Przydzielanie stanowisk","docId":"test/parking-stand-allocation","unlisted":false}],"href":"/category/demo-do-kalibracji"},{"type":"category","label":"Dla tw\xf3rc\xf3w","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/contributors/style-guidelines","label":"Wytyczne do pisania artyku\u0142\xf3w","docId":"contributors/style-guidelines","unlisted":false},{"type":"link","href":"/contributors/creating-pull-requests","label":"Dodawanie zmian do Wiki","docId":"contributors/creating-pull-requests","unlisted":false},{"type":"link","href":"/contributors/issues-reporting","label":"Zg\u0142aszanie b\u0142\u0119d\xf3w","docId":"contributors/issues-reporting","unlisted":false},{"type":"link","href":"/contributors/docusaurus-local-dev-server","label":"Docusaurus lokalnie","docId":"contributors/docusaurus-local-dev-server","unlisted":false},{"type":"category","label":"Dokumentacja Docusaurus","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/contributors/docusaurus-tutorials/docusaurus-intro","label":"Docusaursu Intro","docId":"contributors/docusaurus-tutorials/docusaurus-intro","unlisted":false},{"type":"category","label":"Tutorial - Basics","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-basics/create-a-page","label":"Create a Page","docId":"contributors/docusaurus-tutorials/tutorial-basics/create-a-page","unlisted":false},{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-basics/create-a-document","label":"Create a Document","docId":"contributors/docusaurus-tutorials/tutorial-basics/create-a-document","unlisted":false},{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-basics/create-a-blog-post","label":"Create a Blog Post","docId":"contributors/docusaurus-tutorials/tutorial-basics/create-a-blog-post","unlisted":false},{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-basics/markdown-features","label":"Markdown Features","docId":"contributors/docusaurus-tutorials/tutorial-basics/markdown-features","unlisted":false},{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-basics/deploy-your-site","label":"Deploy your site","docId":"contributors/docusaurus-tutorials/tutorial-basics/deploy-your-site","unlisted":false},{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-basics/congratulations","label":"Congratulations!","docId":"contributors/docusaurus-tutorials/tutorial-basics/congratulations","unlisted":false}],"href":"/category/tutorial---basics"},{"type":"category","label":"Tutorial - Extras","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-extras/manage-docs-versions","label":"Manage Docs Versions","docId":"contributors/docusaurus-tutorials/tutorial-extras/manage-docs-versions","unlisted":false},{"type":"link","href":"/contributors/docusaurus-tutorials/tutorial-extras/translate-your-site","label":"Translate your site","docId":"contributors/docusaurus-tutorials/tutorial-extras/translate-your-site","unlisted":false}],"href":"/category/tutorial---extras"}],"href":"/category/dokumentacja-docusaurus"}],"href":"/category/dla-tw\xf3rc\xf3w"},{"type":"category","label":"hems","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/hems/hems-ops","label":"Operacje HEMS","docId":"hems/hems-ops","unlisted":false}]}]},"docs":{"basic/air-traffic-management-radiotelephony":{"id":"basic/air-traffic-management-radiotelephony","title":"Radiotelefonia i frazeologia","description":"Komunikacja radiowa jest jednym z podstawowych element\xf3w zapewnienia bezpiecze\u0144stwa ruchu lotniczego. W odr\xf3\u017Cnieniu od zwyk\u0142ej rozmowy, ka\u017Cda transmisja radiowa ma okre\u015Blon\u0105 struktur\u0119, wykorzystuje ustandaryzowan\u0105 frazeologi\u0119 oraz podlega \u015Bcis\u0142ym zasadom okre\u015Blonym przez dokument ICAO Doc 9432 \u2013 Manual of Radiotelephony. Celem tych zasad jest zapewnienie, aby ka\u017Cda informacja zosta\u0142a przekazana kr\xf3tko, jednoznacznie i bez mo\u017Cliwo\u015Bci b\u0142\u0119dnej interpretacji.","sidebar":"defaultSidebar"},"basic/air-traffic-management/air-traffic-management":{"id":"basic/air-traffic-management/air-traffic-management","title":"Zarz\u0105dzanie ruchem lotniczym","description":"","sidebar":"defaultSidebar"},"basic/air-traffic-management/air-traffic-management-ATC-transmissions":{"id":"basic/air-traffic-management/air-traffic-management-ATC-transmissions","title":"Zezwolenia i instrukcje ATC","description":"Ka\u017Cda transmisja wydawana przez kontrolera ruchu lotniczego ma okre\u015Blony cel. Jedne komunikaty upowa\u017Cniaj\u0105 pilota do wykonania okre\u015Blonej czynno\u015Bci, inne nakazuj\u0105 wykonanie konkretnego dzia\u0142ania, a jeszcze inne maj\u0105 jedynie charakter informacyjny i s\u0142u\u017C\u0105 przekazaniu informacji istotnych dla bezpiecznego przebiegu lotu.","sidebar":"defaultSidebar"},"basic/air-traffic-management/air-traffic-management-flight-levels":{"id":"basic/air-traffic-management/air-traffic-management-flight-levels","title":"Poziomy lotu","description":"Wyobra\u017Amy sobie dw\xf3ch pilot\xf3w lec\u0105cych obok siebie na tej samej wysoko\u015Bci. Ka\u017Cdy z nich korzysta jednak z innego ustawienia wysoko\u015Bciomierza, wynikaj\u0105cego z lokalnego ci\u015Bnienia atmosferycznego np. z lotniska ich odlotu. W efekcie wskazania na wysoko\u015Bciomierzach r\xf3\u017Cni\u0105 si\u0119, mimo \u017Ce rzeczywiste po\u0142o\u017Cenie w przestrzeni jest identyczne. Aby wyeliminowa\u0107 ten problem, w lotnictwie wprowadzono system poziom\xf3w lotu (Flight Levels, FL) \u2013 wsp\xf3lny, standardowy system odniesienia wysoko\u015Bci oparty o sta\u0142e ci\u015Bnienie 1013,25 hPa (QNE). Dzi\u0119ki temu wszystkie statki powietrzne powy\u017Cej okre\u015Blonego poziomu korzystaj\u0105 z tego samego punktu odniesienia, co umo\u017Cliwia jednoznaczn\u0105 separacj\u0119 pionow\u0105.","sidebar":"defaultSidebar"},"basic/air-traffic-management/air-traffic-management-practical-skills":{"id":"basic/air-traffic-management/air-traffic-management-practical-skills","title":"Podstawowe umiej\u0119tno\u015Bci praktyczne znajduj\u0105ce zastosowanie w ruchu lotniczym","description":"Znajomo\u015B\u0107 procedur, frazeologii oraz przepis\xf3w stanowi oczywi\u015Bcie podstaw\u0119 pracy kontrolera ruchu lotniczego; sama wiedza nie wystarczy jednak do sprawnego i bezpiecznego prowadzenia ruchu. W praktyce r\xf3wnie istotne s\u0105 umiej\u0119tno\u015Bci, kt\xf3rych nie da si\u0119 w pe\u0142ni opisa\u0107 za pomoc\u0105 przepis\xf3w ICAO, a kt\xf3re ka\u017Cdego dnia decyduj\u0105 o jako\u015Bci \u015Bwiadczonej s\u0142u\u017Cby. Do najwa\u017Cniejszych z nich nale\u017C\u0105:","sidebar":"defaultSidebar"},"basic/aircraft/aircraft":{"id":"basic/aircraft/aircraft","title":"Statki powietrzne","description":"Statki powietrzne r\xf3\u017Cni\u0105 si\u0119 mi\u0119dzy sob\u0105 nie tylko wielko\u015Bci\u0105, typem nap\u0119du, osi\u0105gami, czy przeznaczeniem, ale r\xf3wnie\u017C charakterystyk\u0105 lotu oraz wp\u0142ywem, jaki wywieraj\u0105 na inne statki powietrzne. Dla potrzeb organizacji ruchu lotniczego stosuje si\u0119 r\xf3\u017Cne systemy klasyfikacji, kt\xf3re wykorzystywane s\u0105 m.in. przy planowaniu separacji, doborze procedur oraz prowadzeniu ruchu lotniczego. Nie istnieje jeden uniwersalny podzia\u0142 obejmuj\u0105cy wszystkie aspekty wykonywania lot\xf3w. Statki powietrzne klasyfikowane s\u0105 wed\u0142ug r\xf3\u017Cnych kryteri\xf3w, zale\u017Cnie od celu, jakiemu dana klasyfikacja s\u0142u\u017Cy.","sidebar":"defaultSidebar"},"basic/aviation-law/aviation-law":{"id":"basic/aviation-law/aviation-law","title":"Prawo lotnicze","description":"","sidebar":"defaultSidebar"},"basic/aviation-law/aviation-law-airspace":{"id":"basic/aviation-law/aviation-law-airspace","title":"Przestrze\u0144 powietrzna","description":"Przestrze\u0144 powietrzna to po prostu wycinek atmosfery. Ruch statk\xf3w powietrznych od startu do l\u0105dowania z definicji odbywa si\u0119 w\u0142a\u015Bnie w  przestrzeni powietrznej. Cechy tej przestrzeni w danym miejscu decyduj\u0105 mi\u0119dzy innymi o tym, czy lot w og\xf3le jest dopuszczalny, wed\u0142ug jakich przepis\xf3w mo\u017Cna go wykonywa\u0107 (tylko IFR, czy tak\u017Ce VFR), czy zapewniana jest s\u0142u\u017Cba kontroli ruchu lotniczego, czy te\u017C na jakich zasadach statkom powietrznym w przestrzeni kontrolowanej zapewniana jest separacja. Zar\xf3wno z punktu widzenia kontrolera, jak i pilota, ogromne znaczenie ma umiej\u0119tno\u015B\u0107 interpretacji map, czyli przede wszystkim prze\u0142o\u017Cenia ich na tr\xf3jwymiarowy obraz przestrzeni. Jako kontroler musisz na tej podstawie ustali\u0107 zar\xf3wno w\u0142asne zadania, jak i by\u0107 w stanie reagowa\u0107, je\u015Bli za\u0142oga statku powietrznego naruszy swoje obowi\u0105zki (np. bez zezwolenia wleci do przestrzeni kontrolowanej).","sidebar":"defaultSidebar"},"basic/aviation-law/aviation-law-intro":{"id":"basic/aviation-law/aviation-law-intro","title":"Wprowadzenie do prawa lotniczego","description":"Celem sieci VATSIM jest mo\u017Cliwie wierne symulowanie rzeczywistego ruchu lotniczego (as real as it gets). Oczywi\u015Bcie nie wszystko mo\u017Ce dzia\u0142a\u0107 \\"tak samo\\", jak naprawd\u0119. Nie latamy prawdziwymi samolotami, nie obs\u0142ugujemy prawdziwej przestrzeni powietrznej, nie nadajemy przez prawdziwe radio, a zar\xf3wno za\u0142ogi, jak i kontrolerzy nie przechodz\u0105 przez r\xf3wnie rygorystyczny proces szkolenia. W \u017Cadnym wypadku nie oznacza to jednak, \u017Ce na VATSIM nie obowi\u0105zuj\u0105 regu\u0142y. Cz\u0119\u015B\u0107 z nich jest wprost oparta na obowi\u0105zuj\u0105cym prawie lotniczym, a cz\u0119\u015B\u0107 zosta\u0142a ustalona specjalnie dla potrzeb naszej spo\u0142eczno\u015Bci.","sidebar":"defaultSidebar"},"basic/aviation-law/aviation-law-organisations":{"id":"basic/aviation-law/aviation-law-organisations","title":"Instytucje mi\u0119dzynarodowe w kontek\u015Bcie VATSIM","description":"Lotnictwo od dawna opiera si\u0119 na mi\u0119dzynarodowej wsp\xf3\u0142pracy. Jej przejawem w lotnictwie rzeczywistym s\u0105 organizacje mi\u0119dzynarodowe (mi\u0119dzyrz\u0105dowe) dzia\u0142aj\u0105ce na podstawie um\xf3w mi\u0119dzynarodowych. Z kolei sie\u0107 VATSIM oparta jest na hierarchii, w kt\xf3rej organizacje krajowe (subdywizje) tworz\u0105 wi\u0119ksze struktury.","sidebar":"defaultSidebar"},"basic/aviation-law/aviation-law-polish-orgs":{"id":"basic/aviation-law/aviation-law-polish-orgs","title":"Lokalne organizacje istotne dla VATSIM","description":"Polish vACC","sidebar":"defaultSidebar"},"basic/equipment/equipment":{"id":"basic/equipment/equipment","title":"Urz\u0105dzenia i systemy","description":"","sidebar":"defaultSidebar"},"basic/general":{"id":"basic/general","title":"Zagadnienia og\xf3lne","description":"","sidebar":"defaultSidebar"},"basic/human-factor/human-factor":{"id":"basic/human-factor/human-factor","title":"Czynniki ludzkie","description":"","sidebar":"defaultSidebar"},"basic/human-factor/human-factor-principles":{"id":"basic/human-factor/human-factor-principles","title":"Podej\u015Bcie do innych u\u017Cytkownik\xf3w","description":"Jedn\u0105 z najwi\u0119kszych r\xf3\u017Cnic pomi\u0119dzy rzeczywist\u0105 s\u0142u\u017Cb\u0105 kontroli ruchu lotniczego a sprawowaniem tej\u017Ce w sieci VATSIM jest poziom wyszkolenia pocz\u0105tkuj\u0105cych pilot\xf3w w sieci. Obok pilot\xf3w z wieloletnim sta\u017Cem regularnie pojawiaj\u0105 si\u0119 osoby wykonuj\u0105ce sw\xf3j pierwszy lot online, ucz\u0105ce si\u0119 zar\xf3wno zasad komunikacji radiowej, jak i obs\u0142ugi symulatora czy te\u017C wybranego przez siebie statku powietrznego - nierzadko jest to B737 czy A320. O ile kontrolerzy przechodz\u0105 wieloetapowe szkolenie zanim zaczn\u0105 samodzielnie obsadza\u0107 pozycje w ramach danego vFIR, o tyle od pilot\xf3w nie wymaga si\u0119 przechodzenia obowi\u0105zkowego szkolenia przed rozpocz\u0119ciem lot\xf3w w sieci.","sidebar":"defaultSidebar"},"basic/meteorology/clouds":{"id":"basic/meteorology/clouds","title":"clouds","description":"Clouds are pretty","sidebar":"defaultSidebar"},"basic/meteorology/meteorology":{"id":"basic/meteorology/meteorology","title":"Meteorologia update","description":"","sidebar":"defaultSidebar"},"basic/meteorology/meteorology-basics":{"id":"basic/meteorology/meteorology-basics","title":"Podstawowe zjawiska meteorologiczne oraz ich wp\u0142yw na lotnictwo","description":"Meteorologia to nauka zajmuj\u0105ca si\u0119 badaniem atmosfery ziemskiej, jej proces\xf3w oraz zjawisk zachodz\u0105cych w warstwie przyziemnej i wy\u017Cszych warstwach troposfery. W lotnictwie jej znaczenie jest kluczowe, poniewa\u017C warunki meteorologiczne bezpo\u015Brednio wp\u0142ywaj\u0105 na bezpiecze\u0144stwo i organizacj\u0119 ruchu lotniczego oraz na osi\u0105gi statk\xf3w powietrznych.","sidebar":"defaultSidebar"},"basic/meteorology/meteorology-sources":{"id":"basic/meteorology/meteorology-sources","title":"\u0179r\xf3d\u0142a danych meteorologicznych","description":"Znajomo\u015B\u0107 podstawowych zjawisk meteorologicznych opisanych w poprzednim rozdziale to dopiero pierwszy krok ku ich w\u0142a\u015Bciwemu wykorzystaniu w lotnictwie. W codziennej pracy kontrolera ruchu lotniczego oraz pilota decyzje operacyjne podejmowane s\u0105 m.in. na podstawie oficjalnych depesz i prognoz meteorologicznych, przygotowywanych wed\u0142ug jednolitych standard\xf3w ICAO oraz \u015Awiatowej Organizacji Meteorologicznej (WMO).","sidebar":"defaultSidebar"},"basic/navigation/navigation":{"id":"basic/navigation/navigation","title":"Nawigacja","description":"","sidebar":"defaultSidebar"},"basic/special_unsafe_situations/special-and-unsafe-situations":{"id":"basic/special_unsafe_situations/special-and-unsafe-situations","title":"Sytuacje szczeg\xf3lne i niebezpieczne","description":"Sytuacje szczeg\xf3lne i niebezpieczne to zdarzenia, kt\xf3re wymagaj\u0105 od za\u0142ogi statku powietrznego oraz s\u0142u\u017Cb ruchu lotniczego podj\u0119cia dodatkowych dzia\u0142a\u0144 w celu zapewnienia bezpiecze\u0144stwa lotu.","sidebar":"defaultSidebar"},"contributors/creating-pull-requests":{"id":"contributors/creating-pull-requests","title":"Dodawanie zmian do Wiki przez pull requesty","description":"Artyku\u0142 przedstawia podstawowy proces wprowadzania zmian do bazy wiedzy - od utworzenia w\u0142asnej ga\u0142\u0119zi (branch), przez dodawanie i modyfikowanie plik\xf3w oraz katalog\xf3w, a\u017C po utworzenie Pull Requesta, kt\xf3ry umo\u017Cliwia recenzj\u0119 zmian i w\u0142\u0105czenie tre\u015Bci do g\u0142\xf3wnej wersji repozytorium. Opisany workflow skupia si\u0119 na dodawaniu zmian z u\u017Cyciem wy\u0142\u0105cznie interfejsu strony GitHub, wi\u0119c znajomo\u015B\u0107 dodatkowych narz\u0119dzi do pracy z Gitem nie jest wymagana.","sidebar":"defaultSidebar"},"contributors/docusaurus-local-dev-server":{"id":"contributors/docusaurus-local-dev-server","title":"Jak uruchomi\u0107 PLVACC wiki lokalnie na komputerze?","description":"Po co w og\xf3le odpala\u0107 wiki lokalnie? Jest kilka powod\xf3w, zaczn\u0119 jednak od takiego, dla kt\xf3rego nie warto przechodzi\u0107 przez ten proces. Nie warto si\u0119 m\u0119czy\u0107, je\u015Bli chcesz tylko zobaczy\u0107, jak b\u0119dzie wygl\u0105da\u0142 Tw\xf3j plik .md po udost\u0119pnieniu na wiki. Wygeneruje to ka\u017Cdy edytor wspieraj\u0105cy ten format, jak Zettlr, Obsidian czy VS Code.","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/docusaurus-intro":{"id":"contributors/docusaurus-tutorials/docusaurus-intro","title":"Docusaursu Intro","description":"Let\'s discover Docusaurus in less than 5 minutes.","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-basics/congratulations":{"id":"contributors/docusaurus-tutorials/tutorial-basics/congratulations","title":"Congratulations!","description":"You have just learned the basics of Docusaurus and made some changes to the initial template.","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-basics/create-a-blog-post":{"id":"contributors/docusaurus-tutorials/tutorial-basics/create-a-blog-post","title":"Create a Blog Post","description":"Docusaurus creates a page for each blog post, but also a blog index page, a tag system, an RSS feed...","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-basics/create-a-document":{"id":"contributors/docusaurus-tutorials/tutorial-basics/create-a-document","title":"Create a Document","description":"Documents are groups of pages connected through:","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-basics/create-a-page":{"id":"contributors/docusaurus-tutorials/tutorial-basics/create-a-page","title":"Create a Page","description":"Add Markdown or React files to src/pages to create a standalone page:","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-basics/deploy-your-site":{"id":"contributors/docusaurus-tutorials/tutorial-basics/deploy-your-site","title":"Deploy your site","description":"Docusaurus is a static-site-generator (also called Jamstack).","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-basics/markdown-features":{"id":"contributors/docusaurus-tutorials/tutorial-basics/markdown-features","title":"Markdown Features","description":"Docusaurus supports Markdown and a few additional features.","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-extras/manage-docs-versions":{"id":"contributors/docusaurus-tutorials/tutorial-extras/manage-docs-versions","title":"Manage Docs Versions","description":"Docusaurus can manage multiple versions of your docs.","sidebar":"defaultSidebar"},"contributors/docusaurus-tutorials/tutorial-extras/translate-your-site":{"id":"contributors/docusaurus-tutorials/tutorial-extras/translate-your-site","title":"Translate your site","description":"Let\'s translate docs/intro.md to French.","sidebar":"defaultSidebar"},"contributors/issues-reporting":{"id":"contributors/issues-reporting","title":"Zg\u0142aszanie b\u0142\u0119d\xf3w","description":"Do\u0142o\u017Cyli\u015Bmy wszelkich stara\u0144, \u017Ceby materia\u0142y zawarte na PLVACC Wiki by\u0142y jak najbardziej rzetelne i poprawne. Je\u015Bli jednak znalaz\u0142e\u015B b\u0142\u0105d, to b\u0119dziemy wdzi\u0119czni, je\u015Bli go zg\u0142osisz. Mo\u017Cesz to zrobi\u0107 na kilka sposob\xf3w:","sidebar":"defaultSidebar"},"contributors/style-guidelines":{"id":"contributors/style-guidelines","title":"Wytyczne do pisania artyku\u0142\xf3w","description":"Nazwa i lokacja pliku","sidebar":"defaultSidebar"},"hems/hems-ops":{"id":"hems/hems-ops","title":"Operacje HEMS","description":"HEMS (Helicopter Emergency Medical Service) to \u015Amig\u0142owcowa S\u0142u\u017Cba Ratownictwa Medycznego, kt\xf3rej zadaniem jest wykonywanie lot\xf3w zwi\u0105zanych z ratowaniem \u017Cycia i zdrowia ludzi. Operacje HEMS obejmuj\u0105 mi\u0119dzy innymi transport poszkodowanych, pacjent\xf3w wymagaj\u0105cych pilnej pomocy medycznej oraz transport narz\u0105d\xf3w przeznaczonych do przeszczep\xf3w. Cho\u0107 zdecydowana wi\u0119kszo\u015B\u0107 takich lot\xf3w wykonywana jest \u015Bmig\u0142owcami, analogiczne zadania mog\u0105 realizowa\u0107 r\xf3wnie\u017C samoloty. W Polsce s\u0142u\u017Cb\u0119 HEMS zapewnia Lotnicze Pogotowie Ratunkowe, w skr\xf3cie LPR.","sidebar":"defaultSidebar"},"regulations/atc-school-requlations":{"id":"regulations/atc-school-requlations","title":"Regulamin Szko\u0142y Kontroler\xf3w w PLVACC","description":"\xa71 Cel i zakres regulaminu","sidebar":"defaultSidebar"},"s1/aerodrome/aerodromes":{"id":"s1/aerodrome/aerodromes","title":"Lotniska","description":"Lotnisko jest podstawowym elementem infrastruktury lotniczej i miejscem, w kt\xf3rym rozpoczyna si\u0119 oraz ko\u0144czy wi\u0119kszo\u015B\u0107 operacji lotniczych. Dla kontrolera ruchu lotniczego oraz pilota znajomo\u015B\u0107 budowy lotniska, jego element\xf3w i stosowanego nazewnictwa jest niezb\u0119dna do prawid\u0142owego wykonywania czynno\u015Bci operacyjnych. Zrozumienie przeznaczenia poszczeg\xf3lnych cz\u0119\u015Bci lotniska u\u0142atwia interpretacj\u0119 map lotniskowych, prowadzenie korespondencji radiowej oraz w\u0142a\u015Bciwe wykonywanie instrukcji kontroli ruchu lotniczego.","sidebar":"defaultSidebar"},"s1/delivery/delivery":{"id":"s1/delivery/delivery","title":"Clearance - delivery","description":"","sidebar":"defaultSidebar"},"s1/delivery/delivery-flight-plan-validation":{"id":"s1/delivery/delivery-flight-plan-validation","title":"Sprawdzenie poprawno\u015Bci planu lotu","description":"Jednym z pierwszych i kluczowych obowi\u0105zk\xf3w kontrolera ruchu lotniczego (KRL) na pozycji Delivery jest weryfikacja planu lotu z\u0142o\u017Conego przez pilota. Kontroler ma obowi\u0105zek sprawdzi\u0107 i w razie potrzeby poinformowa\u0107 pilota o ewentualnych nieprawid\u0142owo\u015Bciach przed wydaniem zezwolenia na lot.","sidebar":"defaultSidebar"},"s1/ground/ground":{"id":"s1/ground/ground","title":"Kontroler ground","description":"","sidebar":"defaultSidebar"},"s1/S1":{"id":"s1/S1","title":"Rating S1","description":"","sidebar":"defaultSidebar"},"s2/S2":{"id":"s2/S2","title":"Rating S2","description":"","sidebar":"defaultSidebar"},"test/airspace":{"id":"test/airspace","title":"Przestrze\u0144 powietrzna","description":"Przestrze\u0144 powietrzna to po prostu wycinek atmosfery. Ruch statk\xf3w powietrznych od startu do l\u0105dowania z definicji odbywa si\u0119 w\u0142a\u015Bnie w  przestrzeni powietrznej. Cechy tej przestrzeni w danym miejscu decyduj\u0105 mi\u0119dzy innymi o tym, czy lot w og\xf3le jest dopuszczalny, wed\u0142ug jakich przepis\xf3w mo\u017Cna go wykonywa\u0107 (tylko IFR, czy tak\u017Ce VFR), czy zapewniana jest s\u0142u\u017Cba kontroli ruchu lotniczego, czy te\u017C na jakich zasadach statkom powietrznym w przestrzeni kontrolowanej zapewniana jest separacja. Zar\xf3wno z punktu widzenia kontrolera, jak i pilota, ogromne znaczenie ma umiej\u0119tno\u015B\u0107 interpretacji map, czyli przede wszystkim prze\u0142o\u017Cenia ich na tr\xf3jwymiarowy obraz przestrzeni. Jako kontroler musisz na tej podstawie ustali\u0107 zar\xf3wno w\u0142asne zadania, jak i by\u0107 w stanie reagowa\u0107, je\u015Bli za\u0142oga statku powietrznego naruszy swoje obowi\u0105zki (np. bez zezwolenia wleci do przestrzeni kontrolowanej).","sidebar":"defaultSidebar"},"test/arrivals-management":{"id":"test/arrivals-management","title":"1. Zarz\u0105dzanie przylotami","description":"Kontroler na pozycji tower jest odpowiedzialny za odpowiednie zarz\u0105dzanie ruchem przylatuj\u0105cym, w taki spos\xf3b aby zapewni\u0107 mu mo\u017Cliwo\u015B\u0107 wyl\u0105dowania (lub wykonania innej operacji) na wolnej drodze startowej.]","sidebar":"defaultSidebar"},"test/flight-plan-validation":{"id":"test/flight-plan-validation","title":"1. Sprawdzenie poprawno\u015Bci planu lotu.","description":"Jednym z pierwszych i kluczowych obowi\u0105zk\xf3w kontrolera ruchu lotniczego na pozycji delivery jest weryfikacja planu lotu z\u0142o\u017Conego przez pilota. Prawid\u0142owy plan lotu gwarantuje bezpieczn\u0105 separacj\u0119, p\u0142ynno\u015B\u0107 ruchu w przestrzeni powietrznej oraz daje informacje o zamiarach pilota. Kontroler ma obowi\u0105zek sprawdzi\u0107 i w razie potrzeb poinformowa\u0107 pilota o ewentualnych nieprawid\u0142owo\u015Bciach przed wydaniem zezwolenia na lot.","sidebar":"defaultSidebar"},"test/gnd-ground/conditional-instructions":{"id":"test/gnd-ground/conditional-instructions","title":"Instrukcje warunkowe","description":"W sytuacjach, gdy wydanie instrukcji zale\u017Cy od wykonania okre\u015Blonego manewru przez inny statek powietrzny lub pojazd, kontroler mo\u017Ce zastosowa\u0107 instrukcj\u0119 warunkow\u0105. Pozwala ona ograniczy\u0107 liczb\u0119 transmisji radiowych i zwi\u0119kszy\u0107 p\u0142ynno\u015B\u0107 ruchu naziemnego bez negatywnego wp\u0142ywu na poziom bezpiecze\u0144stwa. Zamiast oczekiwa\u0107 na zako\u0144czenie manewru wykonywanego przez inny statek powietrzny i dopiero wtedy wydawa\u0107 kolejn\u0105 instrukcj\u0119, kontroler mo\u017Ce przekaza\u0107 j\u0105 wcze\u015Bniej, wskazuj\u0105c warunek, po kt\xf3rego spe\u0142nieniu za\u0142oga b\u0119dzie mog\u0142a rozpocz\u0105\u0107 wykonywanie manewru. Za\u0142oga nie mo\u017Ce rozpocz\u0105\u0107 wykonywania instrukcji przed spe\u0142nieniem wskazanego warunku.","sidebar":"defaultSidebar"},"test/gnd-ground/deicing":{"id":"test/gnd-ground/deicing","title":"Odladzanie","description":"Operacje odladzania (de-icing) oraz zabezpieczenia przeciwoblodzeniowego (anti-icing) stanowi\u0105 istotny element przygotowania statku powietrznego do odlotu w warunkach wyst\u0119powania oblodzenia, opad\xf3w \u015Bniegu lub marzn\u0105cego deszczu. Ich celem jest zapewnienie, \u017Ce powierzchnie no\u015Bne statku powietrznego s\u0105 wolne od zanieczyszcze\u0144 mog\u0105cych wp\u0142ywa\u0107 negatywnie na ich w\u0142a\u015Bciwo\u015Bci aerodynamiczne.","sidebar":"defaultSidebar"},"test/gnd-ground/GND-duties":{"id":"test/gnd-ground/GND-duties","title":"Zakres obowi\u0105zk\xf3w","description":"Kontroler ruchu naziemnego (Ground Controller, GND) odpowiada za bezpieczne i sprawne prowadzenie statk\xf3w powietrznych poruszaj\u0105cych si\u0119 po polu manewrowym lotniska. Jego podstawowym zadaniem jest taka organizacja ruchu naziemnego, aby statki powietrzne mog\u0142y bezkolizyjnie i w miar\u0119 mo\u017Cliwo\u015Bci w spos\xf3b optymalny dotrze\u0107 z miejsca postojowego do punktu oczekiwania przed pasem startowym (po drodze w razie potrzeby ko\u0142uj\u0105c do miejsca wyznaczonego do odladzania lub pr\xf3b silnik\xf3w) oraz w kierunku przeciwnym \u2013 od pasa do przydzielonego stanowiska postojowego.","sidebar":"defaultSidebar"},"test/gnd-ground/GND-movement":{"id":"test/gnd-ground/GND-movement","title":"Ruch na p\u0142ycie","description":"Po zako\u0144czeniu wypychania lub uruchomienia silnik\xf3w przez za\u0142og\u0119 zadaniem kontrolera GND jest bezpieczne poprowadzenie statku powietrznego do punktu oczekiwania przed pasem startowym. W przypadku przylot\xf3w sytuacja wygl\u0105da odwrotnie: samolot nale\u017Cy w\xf3wczas bezkolizyjnie doprowadzi\u0107 z drogi startowej do przydzielonego stanowiska postojowego.","sidebar":"defaultSidebar"},"test/gnd-ground/parking-stand-allocation":{"id":"test/gnd-ground/parking-stand-allocation","title":"Przydzielanie stanowisk","description":"Odlatuj\u0105ce statki powietrzne","sidebar":"defaultSidebar"},"test/gnd-ground/push-and-start":{"id":"test/gnd-ground/push-and-start","title":"Wypychanie i uruchamianie","description":"Jednym z podstawowych zada\u0144 kontrolera GND jest wydawanie instrukcji dotycz\u0105cych wypychania (pushback) oraz uruchomienia silnik\xf3w (startup). Cho\u0107 w sieci VATSIM procedury te s\u0105 znacznie uproszczone w por\xf3wnaniu z realnymi operacjami lotniczymi (w rzeczywisto\u015Bci wypychanie samolotu jest wykonywane przez obs\u0142ug\u0119 naziemn\u0105 przy u\u017Cyciu holownika), warto zna\u0107 zasady obowi\u0105zuj\u0105ce w prawdziwym \u015Bwiecie i stosowa\u0107 je wsz\u0119dzie tam, gdzie ma to wp\u0142yw na bezpiecze\u0144stwo oraz p\u0142ynno\u015B\u0107 ruchu naziemnego.","sidebar":"defaultSidebar"},"test/parking-stand-allocation":{"id":"test/parking-stand-allocation","title":"Przydzielanie stanowisk","description":"W realnym \u015Bwiecie stanowiska postojowe przydzielane s\u0105 liniom lotniczym oraz obs\u0142ugiwanym przez nie statkom powietrznym z uwzgl\u0119dnieniem wielu czynnik\xf3w, takich jak typ samolotu, przewidywany czas postoju, obs\u0142ugiwane kierunki lot\xf3w (np. Schengen / Non-Schengen) czy chocia\u017Cby koszty, jakie linia musi ponie\u015B\u0107 w zwi\u0105zku z korzystaniem z konkretnych udogodnie\u0144 technicznych (np. r\u0119kaw). Sie\u0107 VATSIM rz\u0105dzi si\u0119 swoimi prawami i jako kontroler cz\u0119sto nie mamy wp\u0142ywu na to, na jakim stanowisku postanowi zalogowa\u0107 si\u0119 dany pilot. Mo\u017Cemy podj\u0105\u0107 interwencj\u0119 (zwracaj\u0105c si\u0119 do pilota z pro\u015Bb\u0105 o ponowne zalogowanie si\u0119 do sieci na prawid\u0142owym stanowisku), je\u015Bli kto\u015B pojawi si\u0119 na stanowisku wyra\u017Anie niedopasowanym do typu samolotu, jaki wybra\u0142 na dany lot.","sidebar":"defaultSidebar"},"welcome":{"id":"welcome","title":"Witaj na wiki PLVACC","description":"Na razie jest tu jeszcze pusto, ale wiele zdolnych os\xf3b wkr\xf3tce zacznie pracowa\u0107 nad wype\u0142nieniem tej strony bardzo warto\u015Bciowymi materia\u0142ami edukacyjnymi.","sidebar":"defaultSidebar"}}}}')}}]);